import { build } from "esbuild";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const entryModulePath = path.join(__dirname, "modules", "index.js");
const GENERATED_BANNER =
  "// Generated from src/template-build/modules. Do not edit this file directly.";

export async function renderBuildScriptTemplate() {
  const result = await build({
    entryPoints: [entryModulePath],
    bundle: true,
    format: "esm",
    platform: "node",
    target: ["node18"],
    packages: "external",
    write: false,
    banner: {
      js: GENERATED_BANNER,
    },
    legalComments: "none",
    logLevel: "silent",
  });

  const outputFile = result.outputFiles?.[0];

  if (!outputFile) {
    throw new Error("Failed to generate build.mjs template.");
  }

  return `${outputFile.text.trim()}\n`;
}
